sql:
SELECT topic_name
FROM mental_health_topics
WHERE topic_category = 'anxiety disorders';

SELECT user_id, feature_confidence_score
FROM user_features
WHERE feature_name = 'engagement';

SELECT COUNT(post_id)
FROM post_features
WHERE feature_name = 'engagement' AND feature_value = 'high';

SELECT post_id, COUNT(topic_id) AS num_topics
FROM post_topics
GROUP BY post_id;

